const MicroAnimations={duration:{fast: 150,normal: 300,slow: 500,slower: 800},easing:{smooth: 'cubic-bezier(0.4,0,0.2,1)',bounce: 'cubic-bezier(0.68,-0.55,0.265,1.55)',elastic: 'cubic-bezier(0.175,0.885,0.32,1.275)'},play(element,animationClass,callback){if(!element)return;element.classList.add(animationClass);element.style.animation=`${animationClass}${this.duration.normal}ms ease forwards`;const handleEnd=()=>{element.classList.remove(animationClass);element.style.animation='';element.removeEventListener('animationend',handleEnd);callback?.();};element.addEventListener('animationend',handleEnd);},shake(element){if(!element)return;const keyframes=[{transform: 'translateX(0)'},{transform: 'translateX(-8px)'},{transform: 'translateX(8px)'},{transform: 'translateX(-8px)'},{transform: 'translateX(8px)'},{transform: 'translateX(0)'}];element.animate(keyframes,{duration: 400,easing: 'ease-in-out'});},pop(element){if(!element)return;const keyframes=[{transform: 'scale(0)',opacity: 0},{transform: 'scale(1.1)',opacity: 1},{transform: 'scale(1)',opacity: 1}];element.animate(keyframes,{duration: 400,easing: 'cubic-bezier(0.175,0.885,0.32,1.275)'});},pulse(element,times=1){if(!element)return;const keyframes=[{transform: 'scale(1)',opacity: 1},{transform: 'scale(1.1)',opacity: 0.8},{transform: 'scale(1)',opacity: 1}];element.animate(keyframes,{duration: 600,easing: 'ease-in-out',iterations: times});},bounce(element){if(!element)return;const keyframes=[{transform: 'translateY(0)',opacity: 0},{transform: 'translateY(-20px)',opacity: 0.5},{transform: 'translateY(0)',opacity: 1}];element.animate(keyframes,{duration: 500,easing: 'cubic-bezier(0.175,0.885,0.32,1.275)'});},fadeIn(element,options={}){if(!element)return;const{fromOpacity=0,duration=300}=options;element.style.opacity=fromOpacity;element.style.transition=`opacity ${duration}ms ease`;requestAnimationFrame(()=>{element.style.opacity=1;});},fadeOut(element,callback){if(!element)return;element.style.transition='opacity 300ms ease,transform 300ms ease';element.style.opacity=0;setTimeout(()=>{callback?.();},300);},slideUp(element){if(!element)return;element.style.transition='transform 400ms ease,opacity 400ms ease';element.style.transform='translateY(-20px)';element.style.opacity=0;},slideDown(element){if(!element)return;element.style.transition='transform 400ms ease,opacity 400ms ease';element.style.transform='translateY(20px)';element.style.opacity=0;},zoomIn(element){if(!element)return;const keyframes=[{transform: 'scale(0.9)',opacity: 0},{transform: 'scale(1)',opacity: 1}];element.animate(keyframes,{duration: 400,easing: 'ease-out'});},countUp(element,from,to,options={}){if(!element)return;const{duration=2000,prefix='',suffix='',decimals=0}=options;const startTime=performance.now();const startValue=from;const endValue=to;const easeOutQuart=(t)=>1-Math.pow(1-t,4);const animate=(currentTime)=>{const elapsed=currentTime-startTime;const progress=Math.min(elapsed/duration,1);const easedProgress=easeOutQuart(progress);const currentValue=startValue+(endValue-startValue)*easedProgress;element.textContent=prefix+currentValue.toFixed(decimals)+suffix;if(progress<1){requestAnimationFrame(animate);}};requestAnimationFrame(animate);},typeWriter(element,text,speed=50){if(!element)return;let index=0;element.textContent='';const type=()=>{if(index<text.length){element.textContent+=text.charAt(index);index++;setTimeout(type,1000/speed);}};type();},gradientShift(element){if(!element)return;element.style.backgroundSize='200% 200%';element.style.transition='background-position 400ms ease';element.addEventListener('mouseenter',()=>{element.style.backgroundPosition='100% 50%';});element.addEventListener('mouseleave',()=>{element.style.backgroundPosition='0% 50%';});},stagger(items,animationClass='stagger-item',delay=50){items.forEach((item,index)=>{item.style.animationDelay=`${index*delay}ms`;this.play(item,animationClass);});},parallax(element,speed=0.5){if(!element)return;const handleScroll=()=>{const rect=element.getBoundingClientRect();const offset=(window.innerHeight-rect.top)*speed;element.style.transform=`translateY(${offset}px)`;};window.addEventListener('scroll',handleScroll,{passive: true});handleScroll();return()=>window.removeEventListener('scroll',handleScroll);},magneticPull(element,strength=0.3){if(!element)return;element.addEventListener('mousemove',(e)=>{const rect=element.getBoundingClientRect();const centerX=rect.left+rect.width/2;const centerY=rect.top+rect.height/2;const deltaX=(e.clientX-centerX)*strength;const deltaY=(e.clientY-centerY)*strength;element.style.transform=`translate(${deltaX}px,${deltaY}px)`;});element.addEventListener('mouseleave',()=>{element.style.transform='translate(0,0)';});},revealText(element){if(!element)return;const text=element.textContent;element.textContent='';element.style.display='inline-block';const words=text.split(' ');words.forEach((word,wordIndex)=>{const wordSpan=document.createElement('span');wordSpan.style.display='inline-block';wordSpan.style.whiteSpace='nowrap';[...word].forEach((char,charIndex)=>{const charSpan=document.createElement('span');charSpan.textContent=char;charSpan.style.display='inline-block';charSpan.style.opacity='0';charSpan.style.transform='translateY(20px)';charSpan.style.transition=`all ${this.duration.normal}ms ease`;charSpan.style.transitionDelay=`${(wordIndex*100)+(charIndex*50)}ms`;wordSpan.appendChild(charSpan);});if(wordIndex<words.length-1){wordSpan.appendChild(document.createTextNode(' '));}element.appendChild(wordSpan);});requestAnimationFrame(()=>{element.querySelectorAll('span span').forEach(span=>{span.style.opacity='1';span.style.transform='translateY(0)';});});},initButtons(){document.querySelectorAll('.btn-gradient-shift').forEach(btn=>{this.gradientShift(btn);});document.querySelectorAll('.btn-magnetic').forEach(btn=>{this.magneticPull(btn,0.2);});},initCards(){document.querySelectorAll('.card-hover-shine').forEach(card=>{card.addEventListener('mousemove',(e)=>{const rect=card.getBoundingClientRect();const x=e.clientX-rect.left;const y=e.clientY-rect.top;card.style.setProperty('--shine-x',`${x}px`);card.style.setProperty('--shine-y',`${y}px`);});});},ripple(button,event){if(!button)return;const existingRipple=button.querySelector('.ripple-effect');if(existingRipple)existingRipple.remove();const ripple=document.createElement('span');ripple.className='ripple-effect';const rect=button.getBoundingClientRect();const size=Math.max(rect.width,rect.height);const x=(event?.clientX||rect.left+rect.width/2)-rect.left-size/2;const y=(event?.clientY||rect.top+rect.height/2)-rect.top-size/2;ripple.style.cssText=` position: absolute;width: ${size}px;height: ${size}px;left: ${x}px;top: ${y}px;border-radius: 50%;background: rgba(255,255,255,0.4);transform: scale(0);animation: ripple-effect 600ms ease-out;pointer-events: none;`;button.style.position='relative';button.style.overflow='hidden';button.appendChild(ripple);setTimeout(()=>ripple.remove(),600);},flip(element,front,back){if(!element||!front||!back)return;element.style.perspective='1000px';front.style.transition='transform 600ms cubic-bezier(0.4,0,0.2,1),opacity 600ms ease';back.style.transition='transform 600ms cubic-bezier(0.4,0,0.2,1),opacity 600ms ease';back.style.opacity='0';back.style.transform='rotateY(180deg)';let isFlipped=false;element.addEventListener('click',()=>{isFlipped=!isFlipped;if(isFlipped){front.style.transform='rotateY(-180deg)';front.style.opacity='0';back.style.transform='rotateY(0)';back.style.opacity='1';}else{front.style.transform='rotateY(0)';front.style.opacity='1';back.style.transform='rotateY(180deg)';back.style.opacity='0';}});},glow(element,color='rgba(99,102,241,0.5)'){if(!element)return;element.style.transition='box-shadow 300ms ease,transform 300ms ease';element.addEventListener('mouseenter',()=>{element.style.boxShadow=`0 0 30px ${color}`;element.style.transform='translateY(-4px)';});element.addEventListener('mouseleave',()=>{element.style.boxShadow='none';element.style.transform='translateY(0)';});},waveText(element){if(!element)return;const text=element.textContent;element.textContent='';element.style.display='inline-block';[...text].forEach((char,index)=>{const span=document.createElement('span');span.textContent=char===' ' ? '\u00A0' : char;span.style.display='inline-block';span.style.animation=`wave 1.5s ease-in-out infinite`;span.style.animationDelay=`${index*0.1}s`;element.appendChild(span);});},tilt(element,maxTilt=15){if(!element)return;element.style.transformStyle='preserve-3d';element.addEventListener('mousemove',(e)=>{const rect=element.getBoundingClientRect();const x=e.clientX-rect.left;const y=e.clientY-rect.top;const centerX=rect.width/2;const centerY=rect.height/2;const rotateX=((y-centerY)/centerY)*-maxTilt;const rotateY=((x-centerX)/centerX)*maxTilt;element.style.transform=`perspective(1000px)rotateX(${rotateX}deg)rotateY(${rotateY}deg)scale3d(1.02,1.02,1.02)`;});element.addEventListener('mouseleave',()=>{element.style.transform='perspective(1000px)rotateX(0)rotateY(0)scale3d(1,1,1)';});},progressRing(element,progress,duration=1000){if(!element)return;const circle=element.querySelector('circle')||element.querySelector('.progress-ring__circle');if(!circle)return;const radius=circle.r.baseVal.value;const circumference=2*Math.PI*radius;circle.style.strokeDasharray=`${circumference}${circumference}`;circle.style.strokeDashoffset=circumference;circle.style.transition=`stroke-dashoffset ${duration}ms ease-in-out`;requestAnimationFrame(()=>{const offset=circumference-(progress/100)*circumference;circle.style.strokeDashoffset=offset;});},observeAnimate(element,animationClass='fade-in-up',options={}){if(!element)return;const{threshold=0.1,rootMargin='0px'}=options;element.style.opacity='0';element.style.willChange='transform,opacity';const observer=new IntersectionObserver((entries)=>{entries.forEach(entry=>{if(entry.isIntersecting){element.classList.add(animationClass);element.style.opacity='1';observer.unobserve(entry.target);}});},{threshold,rootMargin});observer.observe(element);},initScrollAnimations(){document.querySelectorAll('[data-animate]').forEach(el=>{const animation=el.getAttribute('data-animate')||'fade-in-up';this.observeAnimate(el,animation);});}};if(typeof document!=='undefined'){document.addEventListener('DOMContentLoaded',()=>{MicroAnimations.initButtons();MicroAnimations.initCards();MicroAnimations.initScrollAnimations();document.querySelectorAll('.btn,button,[role="button"]').forEach(btn=>{btn.addEventListener('click',(e)=>{MicroAnimations.ripple(btn,e);});});document.querySelectorAll('.card,.widget').forEach(card=>{MicroAnimations.tilt(card,10);});});}if(typeof module!=='undefined'&&module.exports){module.exports={MicroAnimations};}window.MicroAnimations=MicroAnimations;